class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        UnionFind uf = new UnionFind(n);
        for (int[] edge : edges) {
            if (edge[3] == 1) {
                if (!uf.union(edge[0], edge[1])) return -1;
            }
        }
        if (uf.getComponentCount() > 1 && k == 0) return -1;

        Arrays.sort(edges, (a, b) -> a[2] - b[2]);

        int lo = 0, hi = edges.length - 1;
        while (lo < hi) {
            int mid = lo + (hi - lo + 1) / 2;
            if (check(edges, mid, uf, n, k)) lo = mid;
            else hi = mid - 1;
        }

        return check(edges, lo, uf, n, k) ? edges[lo][2] : -1;
    }

    private boolean check(int[][] edges, int idx, UnionFind uf, int n, int k) {
        UnionFind tempUf = new UnionFind(n);
        for (int i = 0; i <= idx; i++) {
            if (edges[i][3] == 1) tempUf.union(edges[i][0], edges[i][1]);
            else if (k > 0) {
                tempUf.union(edges[i][0], edges[i][1]);
                k--;
            }
        }
        for (int[] edge : edges) {
            if (edge[3] == 1) {
                if (!tempUf.isConnected(edge[0], edge[1])) return false;
            }
        }
        return tempUf.getComponentCount() == 1;
    }
}

class UnionFind {
    private int[] parent;
    private int count;

    public UnionFind(int n) {
        parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
        count = n;
    }

    public int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    public boolean union(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX == rootY) return false;
        parent[rootY] = rootX;
        count--;
        return true;
    }

    public boolean isConnected(int x, int y) {
        return find(x) == find(y);
    }

    public int getComponentCount() {
        return count;
    }
}
